    try {
        const logs = JSON.parse(fs.readFileSync(LOG_FILE, 'utf8') || '[]');
        logs.unshift(req.body);
        fs.writeFileSync(LOG_FILE, JSON.stringify(logs.slice(0, 1000), null, 2)); 
        res.sendStatus(200);
